import{_ as o,o as a,c as i,ai as n}from"./chunks/framework.CsYGeNYI.js";const u=JSON.parse('{"title":"CLI Onboarding Reference","description":"","frontmatter":{"summary":"Complete reference for CLI onboarding flow, auth/model setup, outputs, and internals","read_when":["You need detailed behavior for opensoul onboard","You are debugging onboarding results or integrating onboarding clients"],"title":"CLI Onboarding Reference","sidebarTitle":"CLI reference"},"headers":[],"relativePath":"start/wizard-cli-reference.md","filePath":"start/wizard-cli-reference.md","lastUpdated":1771906665000}'),t={name:"start/wizard-cli-reference.md"};function s(l,e,d,r,c,h){return a(),i("div",null,[...e[0]||(e[0]=[n('<h1 id="cli-onboarding-reference" tabindex="-1"><a class="header-anchor" href="#cli-onboarding-reference">#</a> CLI Onboarding Reference</h1><p>This page is the full reference for <code>opensoul onboard</code>. For the short guide, see <a href="/docs/start/wizard">Onboarding Wizard (CLI)</a>.</p><h2 id="what-the-wizard-does" tabindex="-1"><a class="header-anchor" href="#what-the-wizard-does">#</a> What the wizard does</h2><p>Local mode (default) walks you through:</p><ul><li>Model and auth setup (OpenAI Code subscription OAuth, Anthropic API key or setup token, plus MiniMax, GLM, Moonshot, and AI Gateway options)</li><li>Workspace location and bootstrap files</li><li>Gateway settings (port, bind, auth, tailscale)</li><li>Channels and providers (Telegram, WhatsApp, Discord, Google Chat, Mattermost plugin, Signal)</li><li>Daemon install (LaunchAgent or systemd user unit)</li><li>Health check</li><li>Skills setup</li></ul><p>Remote mode configures this machine to connect to a gateway elsewhere. It does not install or modify anything on the remote host.</p><h2 id="local-flow-details" tabindex="-1"><a class="header-anchor" href="#local-flow-details">#</a> Local flow details</h2><h3 id="existing-config-detection" tabindex="-1"><a class="header-anchor" href="#existing-config-detection">#</a> Existing config detection</h3><ul><li>If <code>~/.opensoul/opensoul.json</code> exists, choose Keep, Modify, or Reset.</li><li>Re-running the wizard does not wipe anything unless you explicitly choose Reset (or pass <code>--reset</code>).</li><li>If config is invalid or contains legacy keys, the wizard stops and asks you to run <code>opensoul doctor</code> before continuing.</li><li>Reset uses <code>trash</code> and offers scopes: <ul><li>Config only</li><li>Config + credentials + sessions</li><li>Full reset (also removes workspace)</li></ul></li></ul><h3 id="model-and-auth" tabindex="-1"><a class="header-anchor" href="#model-and-auth">#</a> Model and auth</h3><ul><li>Full option matrix is in <a href="#auth-and-model-options">Auth and model options</a>.</li></ul><h3 id="workspace" tabindex="-1"><a class="header-anchor" href="#workspace">#</a> Workspace</h3><ul><li>Default <code>~/.opensoul/workspace</code> (configurable).</li><li>Seeds workspace files needed for first-run bootstrap ritual.</li><li>Workspace layout: <a href="/docs/concepts/agent-workspace">Agent workspace</a>.</li></ul><h3 id="gateway" tabindex="-1"><a class="header-anchor" href="#gateway">#</a> Gateway</h3><ul><li>Prompts for port, bind, auth mode, and tailscale exposure.</li><li>Recommended: keep token auth enabled even for loopback so local WS clients must authenticate.</li><li>Disable auth only if you fully trust every local process.</li><li>Non-loopback binds still require auth.</li></ul><h3 id="channels" tabindex="-1"><a class="header-anchor" href="#channels">#</a> Channels</h3><ul><li><a href="/docs/channels/whatsapp">WhatsApp</a>: optional QR login</li><li><a href="/docs/channels/telegram">Telegram</a>: bot token</li><li><a href="/docs/channels/discord">Discord</a>: bot token</li><li><a href="/docs/channels/googlechat">Google Chat</a>: service account JSON + webhook audience</li><li><a href="/docs/channels/mattermost">Mattermost</a> plugin: bot token + base URL</li><li><a href="/docs/channels/signal">Signal</a>: optional <code>signal-cli</code> install + account config</li><li><a href="/docs/channels/bluebubbles">BlueBubbles</a>: recommended for iMessage; server URL + password + webhook</li><li><a href="/docs/channels/imessage">iMessage</a>: legacy <code>imsg</code> CLI path + DB access</li><li>DM security: default is pairing. First DM sends a code; approve via <code>opensoul pairing approve &lt;channel&gt; &lt;code&gt;</code> or use allowlists.</li></ul><h3 id="daemon-install" tabindex="-1"><a class="header-anchor" href="#daemon-install">#</a> Daemon install</h3><ul><li>macOS: LaunchAgent <ul><li>Requires logged-in user session; for headless, use a custom LaunchDaemon (not shipped).</li></ul></li><li>Linux and Windows via WSL2: systemd user unit <ul><li>Wizard attempts <code>loginctl enable-linger &lt;user&gt;</code> so gateway stays up after logout.</li><li>May prompt for sudo (writes <code>/var/lib/systemd/linger</code>); it tries without sudo first.</li></ul></li><li>Runtime selection: Node (recommended; required for WhatsApp and Telegram). Bun is not recommended.</li></ul><h3 id="health-check" tabindex="-1"><a class="header-anchor" href="#health-check">#</a> Health check</h3><ul><li>Starts gateway (if needed) and runs <code>opensoul health</code>.</li><li><code>opensoul status --deep</code> adds gateway health probes to status output.</li></ul><h3 id="skills" tabindex="-1"><a class="header-anchor" href="#skills">#</a> Skills</h3><ul><li>Reads available skills and checks requirements.</li><li>Lets you choose node manager: npm or pnpm (bun not recommended).</li><li>Installs optional dependencies (some use Homebrew on macOS).</li></ul><h3 id="finish" tabindex="-1"><a class="header-anchor" href="#finish">#</a> Finish</h3><ul><li>Summary and next steps, including iOS, Android, and macOS app options.</li></ul><blockquote><p><strong>Note:</strong> If no GUI is detected, the wizard prints SSH port-forward instructions for the Control UI instead of opening a browser. If Control UI assets are missing, the wizard attempts to build them; fallback is <code>pnpm ui:build</code> (auto-installs UI deps).</p></blockquote><h2 id="remote-mode-details" tabindex="-1"><a class="header-anchor" href="#remote-mode-details">#</a> Remote mode details</h2><p>Remote mode configures this machine to connect to a gateway elsewhere.</p><blockquote><p><strong>Info:</strong> Remote mode does not install or modify anything on the remote host.</p></blockquote><p>What you set:</p><ul><li>Remote gateway URL (<code>ws://...</code>)</li><li>Token if remote gateway auth is required (recommended)</li></ul><blockquote><p><strong>Note:</strong></p><ul><li>If gateway is loopback-only, use SSH tunneling or a tailnet.</li><li>Discovery hints: <ul><li>macOS: Bonjour (<code>dns-sd</code>)</li><li>Linux: Avahi (<code>avahi-browse</code>)</li></ul></li></ul></blockquote><h2 id="auth-and-model-options" tabindex="-1"><a class="header-anchor" href="#auth-and-model-options">#</a> Auth and model options</h2><h3 id="anthropic-api-key-recommended" tabindex="-1"><a class="header-anchor" href="#anthropic-api-key-recommended">#</a> Anthropic API key (recommended)</h3><p>Uses <code>ANTHROPIC_API_KEY</code> if present or prompts for a key, then saves it for daemon use.</p><h3 id="anthropic-oauth-claude-code-cli" tabindex="-1"><a class="header-anchor" href="#anthropic-oauth-claude-code-cli">#</a> Anthropic OAuth (Claude Code CLI)</h3><ul><li>macOS: checks Keychain item &quot;Claude Code-credentials&quot;</li><li>Linux and Windows: reuses <code>~/.claude/.credentials.json</code> if present</li></ul><p>On macOS, choose &quot;Always Allow&quot; so launchd starts do not block.</p><h3 id="anthropic-token-setup-token-paste" tabindex="-1"><a class="header-anchor" href="#anthropic-token-setup-token-paste">#</a> Anthropic token (setup-token paste)</h3><p>Run <code>claude setup-token</code> on any machine, then paste the token. You can name it; blank uses default.</p><h3 id="openai-code-subscription-codex-cli-reuse" tabindex="-1"><a class="header-anchor" href="#openai-code-subscription-codex-cli-reuse">#</a> OpenAI Code subscription (Codex CLI reuse)</h3><p>If <code>~/.codex/auth.json</code> exists, the wizard can reuse it.</p><h3 id="openai-code-subscription-oauth" tabindex="-1"><a class="header-anchor" href="#openai-code-subscription-oauth">#</a> OpenAI Code subscription (OAuth)</h3><p>Browser flow; paste <code>code#state</code>.</p><p>Sets <code>agents.defaults.model</code> to <code>openai-codex/gpt-5.3-codex</code> when model is unset or <code>openai/*</code>.</p><h3 id="openai-api-key" tabindex="-1"><a class="header-anchor" href="#openai-api-key">#</a> OpenAI API key</h3><p>Uses <code>OPENAI_API_KEY</code> if present or prompts for a key, then saves it to <code>~/.opensoul/.env</code> so launchd can read it.</p><p>Sets <code>agents.defaults.model</code> to <code>openai/gpt-5.1-codex</code> when model is unset, <code>openai/*</code>, or <code>openai-codex/*</code>.</p><h3 id="xai-grok-api-key" tabindex="-1"><a class="header-anchor" href="#xai-grok-api-key">#</a> xAI (Grok) API key</h3><p>Prompts for <code>XAI_API_KEY</code> and configures xAI as a model provider.</p><h3 id="opencode-zen" tabindex="-1"><a class="header-anchor" href="#opencode-zen">#</a> OpenCode Zen</h3><p>Prompts for <code>OPENCODE_API_KEY</code> (or <code>OPENCODE_ZEN_API_KEY</code>). Setup URL: <a href="https://opencode.ai/auth" target="_blank" rel="noreferrer">opencode.ai/auth</a>.</p><h3 id="api-key-generic" tabindex="-1"><a class="header-anchor" href="#api-key-generic">#</a> API key (generic)</h3><p>Stores the key for you.</p><h3 id="vercel-ai-gateway" tabindex="-1"><a class="header-anchor" href="#vercel-ai-gateway">#</a> Vercel AI Gateway</h3><p>Prompts for <code>AI_GATEWAY_API_KEY</code>. More detail: <a href="/docs/providers/vercel-ai-gateway">Vercel AI Gateway</a>.</p><h3 id="cloudflare-ai-gateway" tabindex="-1"><a class="header-anchor" href="#cloudflare-ai-gateway">#</a> Cloudflare AI Gateway</h3><p>Prompts for account ID, gateway ID, and <code>CLOUDFLARE_AI_GATEWAY_API_KEY</code>. More detail: <a href="/docs/providers/cloudflare-ai-gateway">Cloudflare AI Gateway</a>.</p><h3 id="minimax-m2-1" tabindex="-1"><a class="header-anchor" href="#minimax-m2-1">#</a> MiniMax M2.1</h3><p>Config is auto-written. More detail: <a href="/docs/providers/minimax">MiniMax</a>.</p><h3 id="synthetic-anthropic-compatible" tabindex="-1"><a class="header-anchor" href="#synthetic-anthropic-compatible">#</a> Synthetic (Anthropic-compatible)</h3><p>Prompts for <code>SYNTHETIC_API_KEY</code>. More detail: <a href="/docs/providers/synthetic">Synthetic</a>.</p><h3 id="moonshot-and-kimi-coding" tabindex="-1"><a class="header-anchor" href="#moonshot-and-kimi-coding">#</a> Moonshot and Kimi Coding</h3><p>Moonshot (Kimi K2) and Kimi Coding configs are auto-written. More detail: <a href="/docs/providers/moonshot">Moonshot AI (Kimi + Kimi Coding)</a>.</p><h3 id="skip" tabindex="-1"><a class="header-anchor" href="#skip">#</a> Skip</h3><p>Leaves auth unconfigured.</p><p>Model behavior:</p><ul><li>Pick default model from detected options, or enter provider and model manually.</li><li>Wizard runs a model check and warns if the configured model is unknown or missing auth.</li></ul><p>Credential and profile paths:</p><ul><li>OAuth credentials: <code>~/.opensoul/credentials/oauth.json</code></li><li>Auth profiles (API keys + OAuth): <code>~/.opensoul/agents/&lt;agentId&gt;/agent/auth-profiles.json</code></li></ul><blockquote><p><strong>Note:</strong> Headless and server tip: complete OAuth on a machine with a browser, then copy <code>~/.opensoul/credentials/oauth.json</code> (or <code>$OPENSOUL_STATE_DIR/credentials/oauth.json</code>) to the gateway host.</p></blockquote><h2 id="outputs-and-internals" tabindex="-1"><a class="header-anchor" href="#outputs-and-internals">#</a> Outputs and internals</h2><p>Typical fields in <code>~/.opensoul/opensoul.json</code>:</p><ul><li><code>agents.defaults.workspace</code></li><li><code>agents.defaults.model</code> / <code>models.providers</code> (if Minimax chosen)</li><li><code>gateway.*</code> (mode, bind, auth, tailscale)</li><li><code>channels.telegram.botToken</code>, <code>channels.discord.token</code>, <code>channels.signal.*</code>, <code>channels.imessage.*</code></li><li>Channel allowlists (Slack, Discord, Matrix, Microsoft Teams) when you opt in during prompts (names resolve to IDs when possible)</li><li><code>skills.install.nodeManager</code></li><li><code>wizard.lastRunAt</code></li><li><code>wizard.lastRunVersion</code></li><li><code>wizard.lastRunCommit</code></li><li><code>wizard.lastRunCommand</code></li><li><code>wizard.lastRunMode</code></li></ul><p><code>opensoul agents add</code> writes <code>agents.list[]</code> and optional <code>bindings</code>.</p><p>WhatsApp credentials go under <code>~/.opensoul/credentials/whatsapp/&lt;accountId&gt;/</code>. Sessions are stored under <code>~/.opensoul/agents/&lt;agentId&gt;/sessions/</code>.</p><blockquote><p><strong>Note:</strong> Some channels are delivered as plugins. When selected during onboarding, the wizard prompts to install the plugin (npm or local path) before channel configuration.</p></blockquote><p>Gateway wizard RPC:</p><ul><li><code>wizard.start</code></li><li><code>wizard.next</code></li><li><code>wizard.cancel</code></li><li><code>wizard.status</code></li></ul><p>Clients (macOS app and Control UI) can render steps without re-implementing onboarding logic.</p><p>Signal setup behavior:</p><ul><li>Downloads the appropriate release asset</li><li>Stores it under <code>~/.opensoul/tools/signal-cli/&lt;version&gt;/</code></li><li>Writes <code>channels.signal.cliPath</code> in config</li><li>JVM builds require Java 21</li><li>Native builds are used when available</li><li>Windows uses WSL2 and follows Linux signal-cli flow inside WSL</li></ul><h2 id="related-docs" tabindex="-1"><a class="header-anchor" href="#related-docs">#</a> Related docs</h2><ul><li>Onboarding hub: <a href="/docs/start/wizard">Onboarding Wizard (CLI)</a></li><li>Automation and scripts: <a href="/docs/start/wizard-cli-automation">CLI Automation</a></li><li>Command reference: <a href="/docs/cli/onboard"><code>opensoul onboard</code></a></li></ul>',84)])])}const m=o(t,[["render",s]]);export{u as __pageData,m as default};
